// Using UE5's built-in SQLiteCore
#include "SQLiteDatabase.h"

FString DBPath = FPaths::Combine(FPaths::ProjectSavedDir(), TEXT("GameData.db"));
FSQLiteDatabase DB;
if (DB.Open(*DBPath, ESQLiteDatabaseOpenMode::ReadWriteCreate)) {
    DB.Execute(TEXT("CREATE TABLE IF NOT EXISTS players (id INTEGER PRIMARY KEY, name TEXT, score INTEGER)"));
    DB.Execute(TEXT("INSERT INTO players (name, score) VALUES ('Player1', 100)"));
    DB.Close();
}

// UPrimaryDataAsset for items
UCLASS()
class UItemDefinition : public UPrimaryDataAsset {
    GENERATED_BODY()
public:
    UPROPERTY(EditDefaultsOnly) FText DisplayName;
    UPROPERTY(EditDefaultsOnly) TSoftObjectPtr<UTexture2D> Icon;
    UPROPERTY(EditDefaultsOnly) int32 MaxStackSize;

    virtual FPrimaryAssetId GetPrimaryAssetId() const override {
        return FPrimaryAssetId("Item", GetFName());
    }
};

